3_real_world_example.code:
const shoppingCart = {
  apples: 3,
  bananas: 2,
  oranges: 5
};

// We want the total amount of fruit. We can't map() the object.
// But we can get an array of just the values!
const quantities = Object.values(shoppingCart); // [3, 2, 5]

const total = quantities.reduce((sum, amount) => sum + amount, 0);
console.log(total); // 10

// Using entries to get both key and value in a loop
for (const [item, amount] of Object.entries(shoppingCart)) {
  console.log(`I bought ${amount} ${item}`);
}

